type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const COMPONENT_BASE = 25;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const PROCESSING_FEE = 5;

function itemBasePremium(item: Item): number {
  if (item.type === "rune") return COMPONENT_BASE;
  return 0;
}

function quotePremium(items: Item[]): number {
  const base = items.reduce((sum, it) => sum + itemBasePremium(it), 0);
  const withFirstIns = base * (1 + FIRST_INSURANCE_SURCHARGE);
  return Math.ceil(withFirstIns) + PROCESSING_FEE;
}

export function runScenario(input: unknown): unknown {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => ({
    premium: quotePremium(step.items),
  }));
  return { results };
}

