import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Empty / trivial ---
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // --- Single main item base premiums (no modifiers; 0-year customer; first quote = first insurance + 10% surcharge; no follow-up discount) ---
  // For a 0-year customer with first quote: sword base 100 + 10 (first ins) = 110 + 5 fee = 115 G

  // --- Components: building block of 3 alike ---
  it("2 runes (0-year first quote) → base 50 + first-ins 5 + fee 5 = 60 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("3 runes (block applies) (0-year first quote) → base 60 + first-ins 6 + fee 5 = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it.todo("4 runes (no block — block requires exactly 3) (0-year first quote) → base 100 + first-ins 10 + fee 5 = 115 G");
  it.todo("7 runes (0-year first quote) → base 175 + first-ins 17.5 (round up) + fee 5 = 198 G");

  // --- Alike components ---
  it.todo("2 runes + 1 moonstone — no block (different types) (0-year first quote) → base 75 + first-ins 7.5 + fee 5 = 83 G");
  it.todo("3 runes + 3 moonstones — two separate blocks (0-year first quote) → base 120 + first-ins 12 + fee 5 = 137 G");

  // --- Cursed surcharge ---
  it.todo("cursed sword (0-year first quote) → 100 base + 50 curse + 10 first-ins + 5 fee = 165 G (newcomer integration example)");

  // --- High enchantment surcharge & thresholds ---
  it.todo("sword with enchantment 5 → high-enchantment surcharge applies; (0-year first quote) 100 + 30 + 10 + 5 = 145 G");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge; (0-year first quote) 100 + 10 + 5 = 115 G");
  it.todo("sword with enchantment 5 and cursed → both surcharges; (0-year first quote) 100 + 50 + 30 + 10 + 5 = 195 G");

  // --- Loyalty threshold ---
  it.todo("customer with exactly 2 years (first quote, plain sword) → 100 base - 20 loyalty + 10 first-ins + 5 fee = 95 G");

  // --- Multi-item modifier scope ---
  it.todo("policy covers cursed sword + plain amulet (0-year first quote) → base 160 + 50 curse + 21 first-ins + 5 fee = 236 G");

  // --- Rounding in MHPCO's favor (premium up) ---
  it.todo("premium calculation that yields 197.5 G → final premium 198 G (rounded up)");

  // --- Long-standing customer integration example ---
  it.todo("3-year customer, second quote, cursed sword enchantment 7 → 160 G (with loyalty, follow-up, first-insurance-per-item)");

  // --- Claim: standard reimbursement ---
  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G (deductible)");
  it.todo("damage to a rune (insurance value 250 G), damage 200 G → payout 100 G (deductible; no special clause)");

  // --- Claim: high enchantment ≥ 8 ---
  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");

  // --- Claim: dragon material ---
  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full reimbursement then deductible)");

  // --- Claim: enchantment ≥ 8 wins when combined with dragon material ---
  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins, then deductible)");
  it.todo("dragon-material sword, exactly enchantment 8, damage 1000 G → payout 400 G (high-enchantment clause then deductible)");

  // --- Claim: deductible per damage event (per damaged item) ---
  it.todo("dragon attack: sword damage 500 + amulet damage 300 → payout 600 G (deductible per item)");

  // --- Claim: multiple items same type ---
  it.todo("policy covers two swords (insurance sum 2000 G, cap 4000 G); dragon attack damages both, two sword damage entries → each gets own deductible");
  it.todo("policy covers one sword; damages array has two sword entries → CLI exits non-zero (whole claim rejected)");

  // --- Cap ---
  it.todo("policy covers sword + amulet → insurance sum 1600 G, cap 3200 G (cap based on unmodified insurance values)");
  it.todo("cursed sword → cap 2000 G (premium modifiers do not raise cap)");
  it.todo("policy covers sword + 3 runes (block) → insurance sum 1750 G; block discount affects premium only, not insurance sum");
  it.todo("sword (cap 2000): two successive claims of 1500 each → first payout 1400 remaining 600; second payout 600 remaining 0");

  // --- Rounding (payouts down, MHPCO favor) ---
  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");

  // --- Errors ---
  it.todo("quote with unknown item type (e.g. broomstick) → CLI exits non-zero; stderr has error; no results on stdout");
  it.todo("claim references damage for item not in policy (e.g. amulet when only sword insured) → CLI exits non-zero with stderr error");
  it.todo("claim references damage with unknown item type → CLI exits non-zero with stderr error");
  it.todo("claim contains a damage entry with negative amount → CLI exits non-zero with stderr error");
});

